const h=$input.item.json.headers||{};
const q=$input.item.json.query||{};
const token=h['x-meta-token'];
const account=h['x-meta-account'];
const action=(q.action||'overview').toLowerCase();
if(!token||!account)return[{json:{error:'Missing Meta credentials'}}];
const GRAPH='https://graph.facebook.com/v19.0';
let result;

if(action==='overview'){
  const r=await fetch(`${GRAPH}/${account}/insights?fields=spend,impressions,clicks,ctr,actions,purchase_roas&date_preset=last_30d&level=account&access_token=${token}`);
  const d=(await r.json()).data?.[0]||{};
  const re=(d.purchase_roas||[]).find(x=>x.action_type==='omni_purchase'||x.action_type==='purchase');
  const pa=(d.actions||[]).find(a=>a.action_type==='purchase'||a.action_type==='omni_purchase');
  result={roas:Math.round((re?parseFloat(re.value):0)*100)/100,total_spend:parseFloat(d.spend||0),total_impressions:parseInt(d.impressions||0),total_clicks:parseInt(d.clicks||0),total_conversions:pa?parseInt(pa.value):0,total_creatives:0};

}else if(action==='campaigns'){
  const[cRes,iRes]=await Promise.all([
    fetch(`${GRAPH}/${account}/campaigns?fields=id,name,status,objective,daily_budget,lifetime_budget,budget_remaining,start_time,stop_time&limit=100&access_token=${token}`),
    fetch(`${GRAPH}/${account}/insights?fields=campaign_id,campaign_name,spend,impressions,clicks,ctr,actions,purchase_roas&level=campaign&date_preset=last_30d&limit=100&access_token=${token}`)
  ]);
  const campaigns=(await cRes.json()).data||[];
  const insightMap={};
  for(const ins of((await iRes.json()).data||[]))insightMap[ins.campaign_id]=ins;
  result=campaigns.map(c=>{
    const ins=insightMap[c.id]||{};
    const re=(ins.purchase_roas||[]).find(x=>x.action_type==='omni_purchase'||x.action_type==='purchase');
    const pa=(ins.actions||[]).find(a=>a.action_type==='purchase'||a.action_type==='omni_purchase');
    return{
      id:c.id,name:c.name,
      status:c.status==='ACTIVE'?'live':c.status==='PAUSED'?'paused':'draft',
      platform:'meta',objective:c.objective||null,
      daily_budget:c.daily_budget?parseFloat(c.daily_budget)/100:null,
      lifetime_budget:c.lifetime_budget?parseFloat(c.lifetime_budget)/100:null,
      roas:re?Math.round(parseFloat(re.value)*100)/100:null,
      total_spend:ins.spend?parseFloat(ins.spend):0,
      impressions:ins.impressions?parseInt(ins.impressions):0,
      clicks:ins.clicks?parseInt(ins.clicks):0,
      ctr:ins.ctr?Math.round(parseFloat(ins.ctr)*100)/100:0,
      conversions:pa?parseInt(pa.value):0
    };
  });

}else if(action==='audiences'){
  const r=await fetch(`${GRAPH}/${account}/customaudiences?fields=id,name,approximate_count,subtype,delivery_status,description,creation_time&limit=100&access_token=${token}`);
  const audiences=((await r.json()).data||[]).map(a=>({
    id:a.id,name:a.name,
    approximate_count:a.approximate_count||0,
    subtype:a.subtype||'CUSTOM',
    delivery_status:a.delivery_status||{},
    description:a.description||'',
    creation_time:a.creation_time||''
  }));
  result={audiences,total:audiences.length};

}else if(action==='pixel'){
  const r=await fetch(`${GRAPH}/${account}/adspixels?fields=id,name,last_fired_time,creation_time,is_created_by_business,owner_business&access_token=${token}`);
  const pixels=((await r.json()).data||[]).map(p=>({
    id:p.id,name:p.name||'Meta Pixel',
    last_fired_time:p.last_fired_time||null,
    creation_time:p.creation_time||null
  }));
  result={pixels,total:pixels.length};

}else{
  result={error:`Unknown action: ${action}`};
}

return[{json:result}];
